 99→            },
100→            icon: (isActive) => (
101→                <svg xmlns="http://www.w3.org/2000/svg" width="24px" height="24px" viewBox="0 0 24 24" fill="none">
102→                    <g>
103→                        <path fillRule="evenodd" clipRule="evenodd" d="M8 1.25C5.37665 1.25 3.25 3.37665 3.25 6V20.4648C3.25 21.7269 4.27311 22.75 5.53518 22.75C5.98634 22.75 6.42739 22.6165 6.80278 22.3662L11.3066 19.3636C11.7265 19.0837 12.2735 19.0837 12.6934 19.3636L17.1972 22.3662C17.5726 22.6165 18.0137 22.75 18.4648 22.75C19.7269 22.75 20.75 21.7269 20.75 20.4648V6C20.75 3.37665 18.6234 1.25 16 1.25H8ZM9 6.75C8.58579 6.75 8.25 7.08579 8.25 7.5C8.25 7.91421 8.58579 8.25 9 8.25H15C15.4142 8.25 15.75 7.91421 15.75 7.5C15.75 7.08579 15.4142 6.75 15 6.75H9Z" fill={isActive ? activeColor : inactiveColor}/>
104→                    </g>
105→                </svg>
106→            ),
107→        },
108→    ];
109→
110→    useEffect(() => {
111→        const scroll = () => {
112→            setShowNavlinks(false);
113→
114→            if (timeOutRef.current) {
115→                clearTimeout(timeOutRef.current);
116→            }
117→
118→            timeOutRef.current = setTimeout(() => {
119→                setShowNavlinks(true);
120→            }, 500);
121→        };
122→
123→        document.addEventListener('scroll', scroll, true);
124→        return () => {
125→            if (timeOutRef.current) {
126→                clearTimeout(timeOutRef.current);
127→            }
128→            document.removeEventListener('scroll', scroll, true);
129→        };
130→    }, []);
131→
132→    return (
133→        <>
134→            {showNavlinks && (
135→                <motion.div
136→                    initial={{ opacity: 0, y: 10 }}
137→                    animate={{ opacity: 1, y: 0, transition: { type: 'spring', stiffness: 300, damping: 25, mass: 0.8 } }}
138→                    exit={{ opacity: 0, y: 20, transition: { duration: 0.2, ease: 'easeOut' } }}
139→                    className="mobile-navlink-container"
140→                >
141→                    <div className="mobile-navlink-icon-container">
142→                        {navLinks.map((link, index) => {
143→                            const isActive = link.path && location.pathname === link.path;
144→
145→                            if (link.type === 'profile') {
146→                                return (
147→                                    <div
148→                                        key={index}
149→                                        className="mobile-navlink-item"
150→                                        onClick={link.action}
151→                                    >
152→                                        <div className="mobile-navlink-profile-container">
153→                                            <img
154→                                                loading="lazy"
155→                                                className={`navlink-profile ${session ? 'navlink-profile-active' : ''}`}
156→                                                src={user?.userData?.[0]?.image_url || '/assets/profile.jpg'}
157→                                                alt="profile"
158→                                            />
159→                                        </div>
160→                                        <p className={`mobile-navlink-label ${session ? 'mobile-navlink-label-active' : ''}`}>
161→                                            {link.label}
162→                                        </p>
163→                                    </div>
164→                                );
165→                            }
166→
167→                            return (
168→                                <div
169→                                    key={index}
170→                                    className="mobile-navlink-item"
171→                                    onClick={() => link.action(link.path)}
172→                                >
173→                                    <div className="mobile-navlink-icons">
174→                                        {link.icon(isActive)}
175→                                        {link.notifCount && (
176→                                            <div className="notification-count">
177→                                                {link.notifCount}
178→                                            </div>
179→                                        )}
180→                                    </div>
181→                                    <p className={`mobile-navlink-label ${isActive ? 'mobile-navlink-label-active' : ''}`}>
182→                                        {link.label}
183→                                    </p>
184→                                    {isActive && <div className="mobile-navlink-active-dot" />}
185→                                </div>
186→                            );
187→                        })}
188→                    </div>
189→                </motion.div>
190→            )}
191→        </>
192→    );
193→};
194→
195→export default MobileNavlink;
