}
.sidebar-links{
    display: flex;
    justify-content: flex-start;
    align-items: center;
    padding: 0.6rem 0.8rem 0.6rem 1rem;
    gap: 0.85rem;
    border-radius: 12px;
    cursor: pointer;
    transition: background-color 0.12s ease;
    font-size: 0.95rem;
