    display: flex;
    flex-direction: column;
    align-items: flex-start;
    justify-content: center;
    gap: 0.05rem;
}
.sidebar-name{
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
    font-size: 0.88rem;
    font-weight: 660;
    letter-spacing: 0.01rem;
    line-height: 1.2;
    margin: 0;
    padding: 0;
    color: var(--text-primary);
}
.sidebar-email{
    font-size: 0.72rem;
